import React from 'react';
import { LogBox } from 'react-native';
import NetInfo from '@react-native-community/netinfo';
import AsyncStorage from '@react-native-community/async-storage';

const LogProvider = ({ children }) => {
  const logNetworkRequest = (config) => {
    console.log('Network Request:', config);
  };

  const logAsyncStorage = async (action, data) => {
    console.debug(`AsyncStorage ${action}:`, data);
  };

  const logUserAction = (action, payload) => {
    console.log(`User Action: ${action}`, payload);
  };

  const logStateChange = (componentName, prevState, currentState) => {
    console.log(
      `State Change - ${componentName}:`,
      JSON.stringify(prevState),
      JSON.stringify(currentState)
    );
  };

  const logAuthenticationToken = (token) => {
    console.debug('Authentication Token:', token);
  };

  const logUserData = (data) => {
    console.log('User Data:', data);
  };

  const logApiResponse = (response) => {
    console.log('API Response:', response);
  };

  LogBox.ignoreLogs(['Warning: ...']); // Ignore excessive warning and informational logs

  NetInfo.addEventListener(state => {
    if (state.isConnected) {
      console.log('Network Connected');
    } else {
      console.log('Network Disconnected');
    }
  });

  const useLog = () => {
    AsyncStorage.getAllKeys().then(keys => {
      keys.forEach(key => {
        AsyncStorage.getItem(key).then(value => logAsyncStorage('Get', { key, value }));
      });
    });

    const handleNetworkRequest = (config) => {
      logNetworkRequest(config);
    };

    const handleAsyncStorage = async (action, data) => {
      logAsyncStorage(action, data);
    };

    const handleUserAction = (action, payload) => {
      logUserAction(action, payload);
    };

    const handleStateChange = (componentName, prevState, currentState) => {
      logStateChange(componentName, prevState, currentState);
    };

    const handleAuthenticationToken = (token) => {
      logAuthenticationToken(token);
    };

    const handleUserData = (data) => {
      logUserData(data);
    };

    const handleApiResponse = (response) => {
      logApiResponse(response);
    };

    return {
      networkRequest: handleNetworkRequest,
      asyncStorage: handleAsyncStorage,
      userAction: handleUserAction,
      stateChange: handleStateChange,
      authenticationToken: handleAuthenticationToken,
      userData: handleUserData,
      apiResponse: handleApiResponse,
    };
  };

  return (
    <>
      {children}
      {useLog()}
    </>
  );
};